    99→    /* --- Section 6: Key mathematical constants (14) --- */
   100→    emit_u(0x3fe62e42fefa39efULL);  /* ln2 ~ 0.6931: sinh(ln2) = 0.75 exactly */
   101→    emit_u(0xbfe62e42fefa39efULL);  /* -ln2 */
   102→    emit(0.5);
   103→    emit(-0.5);
