   116→    /* sinh overflows for x > ~710.47; double exp overflow is ~709.78 */
   117→    emit_u(0x40862e42fefa39efULL);  /* exp overflow threshold: ~709.782 */
   118→    emit_u(0x40862e42fefa39f0ULL);  /* one ULP above exp overflow threshold */
   119→    emit_u(0x40862e42fefa39eeULL);  /* one ULP below exp overflow threshold */
   120→    emit_u(0xc0862e42fefa39efULL);  /* negative exp overflow threshold */
   121→    emit_u(0xc0862e42fefa39f0ULL);  /* one ULP above (toward -Inf) */
   122→    emit_u(0xc0862e42fefa39eeULL);  /* one ULP below (toward zero) */
   123→    emit(710.0);
   124→    emit(-710.0);
   125→
   126→    /* --- Section 8: Small-argument fast-path threshold boundaries (8) --- */
   127→    emit_u(0x3fb0000000000000ULL);  /* 2^-12 ~ 2.44e-4 */
   128→    emit_u(0xbfb0000000000000ULL);  /* -2^-12 */
   129→    emit_u(0x3e50000000000000ULL);  /* 2^-26 ~ 1.49e-8 */
   130→    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
   131→    emit_u(0x3f80000000000000ULL);  /* 2^-7 ~ 7.81e-3 */
   132→    emit_u(0xbf80000000000000ULL);  /* -2^-7 */
   133→    emit_u(0x3f20000000000000ULL);  /* 2^-13 ~ 1.22e-4 */
   134→    emit_u(0xbf20000000000000ULL);  /* -2^-13 */
   135→
   136→    /* --- Section 9: Large arguments (10) --- */
   137→    emit(20.0);
   138→    emit(-20.0);
   139→    emit(50.0);
   140→    emit(-50.0);
   141→    emit(88.0);
   142→    emit(-88.0);
   143→    emit(100.0);
   144→    emit(-100.0);
   145→    emit(500.0);
   146→    emit(-500.0);
