   148→    /* --- Section 10: ULP neighbors of key values and mid-range hard cases (29) --- */
   149→    /* ULP triplet around ln2 */
   150→    emit_u(0x3fe62e42fefa39eeULL);  /* one ULP below ln2 */
   151→    emit_u(0x3fe62e42fefa39f0ULL);  /* one ULP above ln2 */
   152→    emit_u(0xbfe62e42fefa39eeULL);  /* one ULP below -ln2 (toward zero) */
