   195→#ifndef EN_PERF
   196→/* 7. Sweep [0, 100] in 100 steps and [-100, 0] in 100 steps */
   197→static void test_sweep(void)
   198→{
   199→    double hi = 100.0;
   200→    int nsteps = 100;
   201→    double step = hi / (double)nsteps;
   202→
   203→    /* [0, 100] */
   204→    for (int i = 0; i <= nsteps; i++)
   205→        emit((double)i * step);
   206→
   207→    /* [-100, 0] */
   208→    for (int i = 0; i <= nsteps; i++)
   209→        emit(-hi + (double)i * step);
   210→}
   211→
   212→/* 8. Sample [0, 10] every ~0.05 (200 points) */
   213→static void test_exhaustive_small(void)
   214→{
   215→    double hi = 10.0;
   216→    int nsteps = 200;
   217→    double step = hi / (double)nsteps;
   218→
   219→    for (int i = 0; i <= nsteps; i++)
   220→        emit((double)i * step);
   221→}
   222→
   223→/* 9. Random sweep: 300 evenly spaced inputs */
   224→static void test_random_300(void)
   225→{
   226→    double lo = -5.0;
   227→    double hi =  5.0;
   228→    int n = 300;
   229→    for (int i = 0; i < n; i++) {
   230→        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
   231→        emit(x);
   232→    }
   233→}
   234→#endif
